I understand your scenario now. When moving from `dangerous` to `safe`, the events accumulated in the reflexive rule count will not be retracted (this is by design, one important principle: the rules engine never drops events). For this case I recommend you keep track of the count using the context state. For example:

```javascript
var d = require('../libjs/durable');
var m = d.m, s = d.s;
d.statechart('waterValve', {

  // initial state 'init' with two triggers
  init: [{
    to: 'safe',
    whenAll: m.water.lt(100),
    run: function (c) {
      c.s.count = 0;
      console.log('init-->safe: ' + c.m.water);
    }
  },{
    to: 'dangerous',
    whenAll: m.water.gte(100),
    run: function (c) {
      c.s.count = 0;
      console.log('init-->dangerous: ' + c.m.water);
    }
  }],

  // state 'safe'
  safe: [{
    to: 'safe',
    whenAll: m.water.lt(100),
    run: function (c) {
      console.log('safe-->safe: ' + c.m.water);
    }
  },{
    to: 'dangerous',
    whenAll: m.water.gte(100),
    run: function (c) {
      console.log('safe-->dangerous: ' + c.m.water);
	  // TODO : warning
    }
  }],

  // state 'dangerous'
  dangerous: [{
    to: 'safe',
    whenAll: m.water.lt(100),
    run: function (c) {
      c.s.count = 0;
      console.log('dangerous-->safe' + c.m.water);
    }
  },{
    to: 'dangerous',
    whenAll: m.water.gte(100),
    run: function (c) {
      c.s.count += 1;
      console.log('incrementing count');
      // TODO : warning
    }
  },{
    to: 'dangerous',
    whenAll: s.count.eq(3),
    run: function (c) {
      c.s.count = 0;
      console.log('dangerous for 3 times');
      // TODO : warning
    }
  }
  ],
});

d.runAll();
```

Here's a patch:

```
diff --git a/psutil/arch/bsd/netbsd.c b/psutil/arch/bsd/netbsd.c
index f3cfd53..97b3356 100644
--- a/psutil/arch/bsd/netbsd.c
+++ b/psutil/arch/bsd/netbsd.c
@@ -172,15 +172,12 @@ psutil_proc_exe(PyObject *self, PyObject *args) {
     size = sizeof(pathname);
     error = sysctl(mib, 4, NULL, &size, NULL, 0);
     if (error == -1) {
-        PyErr_SetFromErrno(PyExc_OSError);
-        return NULL;
-    }
+        goto error;
 
     error = sysctl(mib, 4, pathname, &size, NULL, 0);
-    if (error == -1) {
-        PyErr_SetFromErrno(PyExc_OSError);
-        return NULL;
-    }
+    if (error == -1)
+        goto error;
+
     if (size == 0 || strlen(pathname) == 0) {
         ret = psutil_pid_exists(pid);
         if (ret == -1)
@@ -191,6 +188,18 @@ psutil_proc_exe(PyObject *self, PyObject *args) {
             strcpy(pathname, "");
     }
     return Py_BuildValue("s", pathname);
+
+error:
+    if (error == -1) {
+        if (error == ENOENT) {
+            ret = psutil_pid_exists(pid);
+            if (ret == 0)
+                return NoSuchProcess();
+        }
+        PyErr_SetFromErrno(PyExc_OSError);
+        return NULL;
+    }
+
 #else
     return Py_BuildValue("s", "");
 #endif
```

